import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './Courses.css';

function Courses() {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchCourses = async () => {
      try {
        const response = await axios.get('http://localhost:8000/api/courses/');
        console.log('API Response:', response.data);
        
        // Handle different response formats
        let coursesData = [];
        if (response.data && response.data.results) {
          coursesData = response.data.results;
        } else if (Array.isArray(response.data)) {
          coursesData = response.data;
        } else if (response.data) {
          coursesData = [response.data];
        }

        // Use placeholder data if no courses are returned
        if (coursesData.length === 0) {
          coursesData = [
            {
              id: 1,
              title: 'Introduction to Wildlife Conservation',
              description: 'Learn the basics of wildlife conservation and its importance in maintaining biodiversity.',
              difficulty: 'Beginner',
              image: null
            },
            {
              id: 2,
              title: 'Advanced Wildlife Tracking',
              description: 'Master the skills needed to track and monitor wildlife in their natural habitats.',
              difficulty: 'Intermediate',
              image: null
            }
          ];
        }

        setCourses(coursesData);
        setLoading(false);
      } catch (err) {
        console.error('Error fetching courses:', err);
        setError('Failed to load courses. Please try again later.');
        setLoading(false);
      }
    };

    fetchCourses();
  }, []);

  if (loading) {
    return <div className="loading">Loading courses...</div>;
  }

  if (error) {
    return (
      <div className="courses">
        <section className="courses-header">
          <h1>Our Courses</h1>
          <p>Explore our comprehensive wildlife conservation courses.</p>
        </section>
        <div className="error-message">
          <p>{error}</p>
        </div>
      </div>
    );
  }

  if (!courses || courses.length === 0) {
    return (
      <div className="courses">
        <section className="courses-header">
          <h1>Our Courses</h1>
          <p>Explore our comprehensive wildlife conservation courses.</p>
        </section>
        <div className="no-courses">
          <p>No courses available at the moment. Please check back later.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="courses">
      <section className="courses-header">
        <h1>Our Courses</h1>
        <p>Explore our comprehensive wildlife conservation courses.</p>
      </section>

      <section className="courses-grid">
        {courses.map((course) => (
          <div key={course.id} className="course-card">
            {course.image && (
              <div className="course-image">
                <img src={course.image} alt={course.title} />
              </div>
            )}
            <div className="course-content">
              <h3>{course.title}</h3>
              <p>{course.description}</p>
              <div className="course-footer">
                <span className="difficulty">{course.difficulty}</span>
                <button className="enroll-button">Enroll Now</button>
              </div>
            </div>
          </div>
        ))}
      </section>
    </div>
  );
}

export default Courses;
